1	/********************************************************************
2	 * This file includes functions to write a Verilog module
3	 * based on its definition in Module Manager
4	 *
5	 * Note that Verilog writer functions are just an outputter for the
6	 * module definition.
7	 * You should NOT modify any content of the module manager
8	 * Please use const keyword to restrict this!
9	 *******************************************************************/
10	#include <algorithm>
11	
12	/* Headers from vtrutil library */
13	#include "vtr_assert.h"
14	
15	/* Headers from openfpgautil library */
16	#include "module_manager_utils.h"
17	#include "openfpga_digest.h"
18	#include "openfpga_naming.h"
19	#include "openfpga_port.h"
20	#include "verilog_module_writer.h"
21	#include "verilog_port_types.h"
22	#include "verilog_writer_utils.h"
23	
24	/* begin namespace openfpga */
25	namespace openfpga {
26	
27	/********************************************************************
28	 * Generate the name of a local wire for a undriven port inside Verilog
29	 * module
30	 *******************************************************************/
31	static std::string generate_verilog_undriven_local_wire_name(
32	  const ModuleManager& module_manager, const ModuleId& parent,
33	  const ModuleId& child, const size_t& instance_id,
34	  const ModulePortId& child_port_id) {
35	  std::string wire_name;
36	  if (!module_manager.instance_name(parent, child, instance_id).empty()) {
37	    wire_name = module_manager.instance_name(parent, child, instance_id);
38	  } else {
39	    wire_name = module_manager.module_name(child) + std::string("_") +
40	                std::to_string(instance_id);
41	    wire_name += std::string("_");
42	  }
43	
44	  wire_name += std::string("_undriven_");
45	  wire_name += module_manager.module_port(child, child_port_id).get_name();
46	
47	  return wire_name;
48	}
49	
50	/********************************************************************
51	 * Name a net for a local wire for a verilog module
52	 * 1. If this is a local wire, name it after the
53	 *<src_module_name>_<instance_id>_<src_port_name>
54	 * 2. If this is not a local wire, name it after the port name of parent module
55	 *
56	 * In addition, it will assign the pin index as well
57	 *
58	 * Restriction: this function requires each net has single driver
59	 * which is definitely always true in circuits.
60	 *******************************************************************/
61	static BasicPort generate_verilog_port_for_module_net(
62	  const ModuleManager& module_manager, const ModuleId& module_id,
63	  const ModuleNetId& module_net) {
64	  BasicPort port_to_return;
65	  /* Check all the sink modules of the net,
66	   * if we have a source module is the current module, this is not local wire
67	   */
68	  for (ModuleNetSrcId src_id :
69	       module_manager.module_net_sources(module_id, module_net)) {
70	    if (module_id ==
71	        module_manager.net_source_modules(module_id, module_net)[src_id]) {
72	      /* Here, this is not a local wire, return the port name of the src_port */
73	      ModulePortId net_src_port =
74	        module_manager.net_source_ports(module_id, module_net)[src_id];
75	      size_t src_pin_index =
76	        module_manager.net_source_pins(module_id, module_net)[src_id];
77	      port_to_return.set(module_manager.module_port(module_id, net_src_port));
78	      port_to_return.set_width(src_pin_index, src_pin_index);
79	      port_to_return.set_origin_port_width(
80	        module_manager.module_port(module_id, net_src_port).get_width());
81	      return port_to_return;
82	    }
83	  }
84	
85	  /* Check all the sink modules of the net */
86	  for (ModuleNetSinkId sink_id :
87	       module_manager.module_net_sinks(module_id, module_net)) {
88	    if (module_id ==
89	        module_manager.net_sink_modules(module_id, module_net)[sink_id]) {
90	      /* Here, this is not a local wire, return the port name of the sink_port
91	       */
92	      ModulePortId net_sink_port =
93	        module_manager.net_sink_ports(module_id, module_net)[sink_id];
94	      size_t sink_pin_index =
95	        module_manager.net_sink_pins(module_id, module_net)[sink_id];
96	      port_to_return.set(module_manager.module_port(module_id, net_sink_port));
97	      port_to_return.set_width(sink_pin_index, sink_pin_index);
98	      port_to_return.set_origin_port_width(
99	        module_manager.module_port(module_id, net_sink_port).get_width());
100	      return port_to_return;
101	    }
102	  }
103	
104	  /* Reach here, this is a local wire */
105	  std::string net_name;
106	
107	  /* Each net must only one 1 source */
108	  VTR_ASSERT(1 ==
109	             module_manager.net_source_modules(module_id, module_net).size());
110	
111	  /* Get the source module */
112	  ModuleId net_src_module =
113	    module_manager.net_source_modules(module_id, module_net)[ModuleNetSrcId(0)];
114	  /* Get the instance id */
115	  size_t net_src_instance = module_manager.net_source_instances(
116	    module_id, module_net)[ModuleNetSrcId(0)];
117	  /* Get the port id */
118	  ModulePortId net_src_port =
119	    module_manager.net_source_ports(module_id, module_net)[ModuleNetSrcId(0)];
120	  /* Get the pin id */
121	  size_t net_src_pin =
122	    module_manager.net_source_pins(module_id, module_net)[ModuleNetSrcId(0)];
123	
124	  /* Load user-defined name if we have it */
125	  if (false == module_manager.net_name(module_id, module_net).empty()) {
126	    net_name = module_manager.net_name(module_id, module_net);
127	  } else {
128	    net_name = module_manager.module_name(net_src_module);
129	    net_name +=
130	      std::string("_") + std::to_string(net_src_instance) + std::string("_");
131	    net_name +=
132	      module_manager.module_port(net_src_module, net_src_port).get_name();
133	  }
134	
135	  port_to_return.set_name(net_name);
136	  port_to_return.set_width(net_src_pin, net_src_pin);
137	  port_to_return.set_origin_port_width(
138	    module_manager.module_port(net_src_module, net_src_port).get_width());
139	  return port_to_return;
140	}
141	
142	/********************************************************************
143	 * Find all the undriven nets that are going to be local wires
144	 * And organize it in a vector of ports
145	 * Verilog wire writter function will use the output of this function
146	 * to write up local wire declaration in Verilog format
147	 *******************************************************************/
148	static void find_verilog_module_local_undriven_wires(
149	  std::map<std::string, std::vector<BasicPort>>& local_wires,
150	  const ModuleManager& module_manager, const ModuleId& module_id,
151	  const std::vector<ModuleManager::e_module_port_type>& port_type_blacklist) {
152	  /* Local wires could also happen for undriven ports of child module */
153	  for (const ModuleId& child : module_manager.child_modules(module_id)) {
154	    for (size_t instance :
155	         module_manager.child_module_instances(module_id, child)) {
156	      for (const ModulePortId& child_port_id :
157	           module_manager.module_ports(child)) {
158	        BasicPort child_port = module_manager.module_port(child, child_port_id);
159	        ModuleManager::e_module_port_type child_port_type =
160	          module_manager.port_type(child, child_port_id);
161	        bool filter_out = false;
162	        for (ModuleManager::e_module_port_type curr_port_type :
163	             port_type_blacklist) {
164	          if (child_port_type == curr_port_type) {
165	            filter_out = true;
166	            break;
167	          }
168	        }
169	        if (filter_out) {
170	          continue;
171	        }
172	        std::vector<size_t> undriven_pins;
173	        for (size_t child_pin : child_port.pins()) {
174	          /* Find the net linked to the pin */
175	          ModuleNetId net = module_manager.module_instance_port_net(
176	            module_id, child, instance, child_port_id, child_pin);
177	          /* We only care undriven ports */
178	          if (ModuleNetId::INVALID() == net) {
179	            undriven_pins.push_back(child_pin);
180	          }
181	        }
182	        if (true == undriven_pins.empty()) {
183	          continue;
184	        }
185	        /* Reach here, we need a local wire, we will create a port only for the
186	         * undriven pins of the port! */
187	        BasicPort instance_port;
188	        instance_port.set_name(generate_verilog_undriven_local_wire_name(
189	          module_manager, module_id, child, instance, child_port_id));
190	        /* We give the same port name as child module, this case happens to
191	         * global ports */
192	        instance_port.set_width(
193	          *std::min_element(undriven_pins.begin(), undriven_pins.end()),
194	          *std::max_element(undriven_pins.begin(), undriven_pins.end()));
195	
196	        local_wires[instance_port.get_name()].push_back(instance_port);
197	      }
198	    }
199	  }
200	}
201	
202	/********************************************************************
203	 * Find all the nets that are going to be local wires
204	 * And organize it in a vector of ports
205	 * Verilog wire writter function will use the output of this function
206	 * to write up local wire declaration in Verilog format
207	 *******************************************************************/
208	static std::map<std::string, std::vector<BasicPort>>
209	find_verilog_module_local_wires(const ModuleManager& module_manager,
210	                                const ModuleId& module_id) {
211	  std::map<std::string, std::vector<BasicPort>> local_wires;
212	
213	  /* Local wires come from the child modules */
214	  for (ModuleNetId module_net : module_manager.module_nets(module_id)) {
215	    /* Bypass dangling nets:
216	     * Xifan Tang: I comment this part because it will shadow our problems in
217	     * creating module graph Indeed this make a robust and a smooth Verilog
218	     * module writing But I do want the module graph create is nice and clean
219	     * !!!
220	     */
221	    /*
222	    if ( (0 == module_manager.net_source_modules(module_id, module_net).size())
223	      && (0 == module_manager.net_source_modules(module_id, module_net).size())
224	    ) { continue;
225	    }
226	    */
227	
228	    /* We only care local wires */
229	    if (false ==
230	        module_net_is_local_wire(module_manager, module_id, module_net)) {
231	      continue;
232	    }
233	    /* Find the name for this local wire */
234	    BasicPort local_wire_candidate = generate_verilog_port_for_module_net(
235	      module_manager, module_id, module_net);
236	    /* Cache the net name, try to find it in the cache.
237	     * If you can find one, it means this port may be mergeable, try to do
238	     * merging. If merge fail, add to the local wire list If you cannot find
239	     * one, it means that this port is not mergeable, add to the local wire list
240	     * immediately.
241	     */
242	    std::map<std::string, std::vector<BasicPort>>::iterator it =
243	      local_wires.find(local_wire_candidate.get_name());
244	    bool merged = false;
245	    if (it != local_wires.end()) {
246	      /* Try to merge to one the port in the list that can absorb the current
247	       * local wire */
248	      for (BasicPort& local_wire :
249	           local_wires[local_wire_candidate.get_name()]) {
250	        /* check if the candidate can be combined to an existing local wire */
251	        if (true ==
252	            two_verilog_ports_mergeable(local_wire, local_wire_candidate)) {
253	          /* Merge the ports */
254	          local_wire =
255	            merge_two_verilog_ports(local_wire, local_wire_candidate);
256	          merged = true;
257	          break;
258	        }
259	      }
260	    }
261	
262	    /* If not merged/not found in the cache, push the port to the list */
263	    if (false == merged) {
264	      local_wires[local_wire_candidate.get_name()].push_back(
265	        local_wire_candidate);
266	    }
267	  }
268	
269	  find_verilog_module_local_undriven_wires(
270	    local_wires, module_manager, module_id,
271	    std::vector<ModuleManager::e_module_port_type>());
272	
273	  return local_wires;
274	}
275	
276	/********************************************************************
277	 * Print a Verilog wire connection
278	 * We search all the sinks of the net,
279	 * if we find a module output, we try to find the next module output
280	 * among the sinks of the net
281	 * For each module output (except the first one), we print a wire connection
282	 *******************************************************************/
283	static void print_verilog_module_output_short_connection(
284	  std::fstream& fp, const ModuleManager& module_manager,
285	  const ModuleId& module_id, const ModuleNetId& module_net,
286	  const bool& little_endian) {
287	  /* Ensure a valid file stream */
288	  VTR_ASSERT(true == valid_file_stream(fp));
289	
290	  bool first_port = true;
291	  BasicPort src_port;
292	
293	  /* We have found a module input, now check all the sink modules of the net */
294	  for (ModuleNetSinkId net_sink :
295	       module_manager.module_net_sinks(module_id, module_net)) {
296	    ModuleId sink_module =
297	      module_manager.net_sink_modules(module_id, module_net)[net_sink];
298	    if (module_id != sink_module) {
299	      continue;
300	    }
301	
302	    /* Find the sink port and pin information */
303	    ModulePortId sink_port_id =
304	      module_manager.net_sink_ports(module_id, module_net)[net_sink];
305	    size_t sink_pin =
306	      module_manager.net_sink_pins(module_id, module_net)[net_sink];
307	    BasicPort sink_port(
308	      module_manager.module_port(module_id, sink_port_id).get_name(), sink_pin,
309	      sink_pin);
310	
311	    /* For the first module output, this is the source port, we do nothing and
312	     * go to the next */
313	    if (true == first_port) {
314	      src_port = sink_port;
315	      /* Flip the flag */
316	      first_port = false;
317	      continue;
318	    }
319	
320	    /* We need to print a wire connection here */
321	    print_verilog_wire_connection(fp, sink_port, src_port, false,
322	                                  little_endian);
323	  }
324	}
325	
326	/********************************************************************
327	 * Print a Verilog wire connection
328	 * We search all the sources of the net,
329	 * if we find a module input, we try to find a module output
330	 * among the sinks of the net
331	 * If we find such a pair, we print a wire connection
332	 *******************************************************************/
333	static void print_verilog_module_local_short_connection(
334	  std::fstream& fp, const ModuleManager& module_manager,
335	  const ModuleId& module_id, const ModuleNetId& module_net,
336	  const bool& little_endian) {
337	  /* Ensure a valid file stream */
338	  VTR_ASSERT(true == valid_file_stream(fp));
339	
340	  for (ModuleNetSrcId net_src :
341	       module_manager.module_net_sources(module_id, module_net)) {
342	    ModuleId src_module =
343	      module_manager.net_source_modules(module_id, module_net)[net_src];
344	    if (module_id != src_module) {
345	      continue;
346	    }
347	    /* Find the source port and pin information */
348	    print_verilog_comment(
349	      fp, std::string("----- Net source id " + std::to_string(size_t(net_src)) +
350	                      " -----"));
351	    ModulePortId src_port_id =
352	      module_manager.net_source_ports(module_id, module_net)[net_src];
353	    size_t src_pin =
354	      module_manager.net_source_pins(module_id, module_net)[net_src];
355	    BasicPort src_port(
356	      module_manager.module_port(module_id, src_port_id).get_name(), src_pin,
357	      src_pin);
358	
359	    /* We have found a module input, now check all the sink modules of the net
360	     */
361	    for (ModuleNetSinkId net_sink :
362	         module_manager.module_net_sinks(module_id, module_net)) {
363	      ModuleId sink_module =
364	        module_manager.net_sink_modules(module_id, module_net)[net_sink];
365	      if (module_id != sink_module) {
366	        continue;
367	      }
368	
369	      /* Find the sink port and pin information */
370	      print_verilog_comment(
371	        fp, std::string("----- Net sink id " +
372	                        std::to_string(size_t(net_sink)) + " -----"));
373	      ModulePortId sink_port_id =
374	        module_manager.net_sink_ports(module_id, module_net)[net_sink];
375	      size_t sink_pin =
376	        module_manager.net_sink_pins(module_id, module_net)[net_sink];
377	      BasicPort sink_port(
378	        module_manager.module_port(module_id, sink_port_id).get_name(),
379	        sink_pin, sink_pin);
380	
381	      /* We need to print a wire connection here */
382	      print_verilog_wire_connection(fp, sink_port, src_port, false,
383	                                    little_endian);
384	    }
385	  }
386	}
387	
388	/********************************************************************
389	 * Print short connections inside a Verilog module
390	 * The short connection is defined as the direct connection
391	 * between an input port of the module and an output port of the module
392	 * This type of connection is not covered when printing Verilog instances
393	 * Therefore, they are covered in this function
394	 *
395	 *            module
396	 *            +-----------------------------+
397	 *            |                             |
398	 *  inputA--->|---------------------------->|--->outputB
399	 *            |                             |
400	 *            |                             |
401	 *            |                             |
402	 *            +-----------------------------+
403	 *******************************************************************/
404	static void print_verilog_module_local_short_connections(
405	  std::fstream& fp, const ModuleManager& module_manager,
406	  const ModuleId& module_id, const bool& little_endian) {
407	  /* Local wires come from the child modules */
408	  for (ModuleNetId module_net : module_manager.module_nets(module_id)) {
409	    /* We only care the nets that indicate short connections */
410	    if (false == module_net_include_local_short_connection(
411	                   module_manager, module_id, module_net)) {
412	      continue;
413	    }
414	    print_verilog_comment(
415	      fp, std::string("----- Local connection due to Wire " +
416	                      std::to_string(size_t(module_net)) + " -----"));
417	    print_verilog_module_local_short_connection(fp, module_manager, module_id,
418	                                                module_net, little_endian);
419	  }
420	}
421	
422	/********************************************************************
423	 * Print output short connections inside a Verilog module
424	 * The output short connection is defined as the direct connection
425	 * between two output ports of the module
426	 * This type of connection is not covered when printing Verilog instances
427	 * Therefore, they are covered in this function
428	 *
429	 *            module
430	 *            +-----------------------------+
431	 *                                          |
432	 *               src------>+--------------->|--->outputA
433	 *                         |                |
434	 *                         |                |
435	 *                         +--------------->|--->outputB
436	 *            +-----------------------------+
437	 *******************************************************************/
438	static void print_verilog_module_output_short_connections(
439	  std::fstream& fp, const ModuleManager& module_manager,
440	  const ModuleId& module_id, const bool& little_endian) {
441	  /* Local wires come from the child modules */
442	  for (ModuleNetId module_net : module_manager.module_nets(module_id)) {
443	    /* We only care the nets that indicate short connections */
444	    if (false == module_net_include_output_short_connection(
445	                   module_manager, module_id, module_net)) {
446	      continue;
447	    }
448	    print_verilog_module_output_short_connection(fp, module_manager, module_id,
449	                                                 module_net, little_endian);
450	  }
451	}
452	
453	/********************************************************************
454	 * Write a Verilog instance to a file
455	 * This function will name the input and output connections to
456	 * the inputs/output or local wires available in the parent module
457	 *
458	 *    Parent_module
459	 *    +-----------------------------+
460	 *    |                             |
461	 *    |       +--------------+      |
462	 *    |       |              |      |
463	 *    |       | child_module |      |
464	 *    |       |  [instance]  |      |
465	 *    |       +--------------+      |
466	 *    |                             |
467	 *    +-----------------------------+
468	 *
469	 *******************************************************************/
470	static void write_verilog_instance_to_file(std::fstream& fp,
471	                                           const ModuleManager& module_manager,
472	                                           const ModuleId& parent_module,
473	                                           const ModuleId& child_module,
474	                                           const size_t& instance_id,
475	                                           const bool& use_explicit_port_map,
476	                                           const bool& little_endian) {
477	  /* Ensure a valid file stream */
478	  VTR_ASSERT(true == valid_file_stream(fp));
479	
480	  /* Print module name */
481	  fp << "\t" << module_manager.module_name(child_module) << " ";
482	  /* Print instance name:
483	   * if we have an instance name, use it;
484	   * if not, we use a default name <name>_<num_instance_in_parent_module>
485	   */
486	  if (true ==
487	      module_manager.instance_name(parent_module, child_module, instance_id)
488	        .empty()) {
489	    fp << generate_instance_name(module_manager.module_name(child_module),
490	                                 instance_id)
491	       << " (" << std::endl;
492	  } else {
493	    fp << module_manager.instance_name(parent_module, child_module, instance_id)
494	       << " (" << std::endl;
495	  }
496	
497	  /* Print each port with/without explicit port map */
498	  /* port type2type mapping */
499	  std::map<ModuleManager::e_module_port_type, enum e_dump_verilog_port_type>
500	    port_type2type_map;
501	  port_type2type_map[ModuleManager::MODULE_GLOBAL_PORT] = VERILOG_PORT_CONKT;
502	  port_type2type_map[ModuleManager::MODULE_GPIN_PORT] = VERILOG_PORT_CONKT;
503	  port_type2type_map[ModuleManager::MODULE_GPOUT_PORT] = VERILOG_PORT_CONKT;
504	  port_type2type_map[ModuleManager::MODULE_GPIO_PORT] = VERILOG_PORT_CONKT;
505	  port_type2type_map[ModuleManager::MODULE_INOUT_PORT] = VERILOG_PORT_CONKT;
506	  port_type2type_map[ModuleManager::MODULE_INPUT_PORT] = VERILOG_PORT_CONKT;
507	  port_type2type_map[ModuleManager::MODULE_OUTPUT_PORT] = VERILOG_PORT_CONKT;
508	  port_type2type_map[ModuleManager::MODULE_CLOCK_PORT] = VERILOG_PORT_CONKT;
509	
510	  /* Port sequence: global, inout, input, output and clock ports, */
511	  size_t port_cnt = 0;
512	  for (const auto& kv : port_type2type_map) {
513	    for (const ModulePortId& child_port_id :
514	         module_manager.module_port_ids_by_type(child_module, kv.first)) {
515	      BasicPort child_port =
516	        module_manager.module_port(child_module, child_port_id);
517	      if (0 != port_cnt) {
518	        /* Do not dump a comma for the first port */
519	        fp << "," << std::endl;
520	      }
521	      /* Print port */
522	      fp << "\t\t";
523	      /* if explicit port map is required, output the port name */
524	      if (true == use_explicit_port_map) {
525	        fp << "." << child_port.get_name() << "(";
526	      }
527	
528	      /* Create the port name and width to be used by the instance */
529	      std::vector<BasicPort> instance_ports;
530	      std::vector<bool> instance_ports_is_single_bit;
531	      for (size_t child_pin : child_port.pins()) {
532	        /* Find the net linked to the pin */
533	        ModuleNetId net = module_manager.module_instance_port_net(
534	          parent_module, child_module, instance_id, child_port_id, child_pin);
535	        BasicPort instance_port;
536	        if (ModuleNetId::INVALID() == net) {
537	          /* We give the same port name as child module, this case happens to
538	           * global ports */
539	          instance_port.set_name(generate_verilog_undriven_local_wire_name(
540	            module_manager, parent_module, child_module, instance_id,
541	            child_port_id));
542	          instance_port.set_width(child_pin, child_pin);
543	          instance_port.set_origin_port_width(
544	            module_manager.module_port(child_module, child_port_id)
545	              .get_width());
546	        } else {
547	          /* Find the name for this child port */
548	          instance_port = generate_verilog_port_for_module_net(
549	            module_manager, parent_module, net);
550	        }
551	        /* Create the port information for the net */
552	        instance_ports.push_back(instance_port);
553	      }
554	      /* Try to merge the ports */
555	      if (little_endian) {
556	        std::reverse(instance_ports.begin(), instance_ports.end());
557	      }
558	      std::vector<BasicPort> merged_ports =
559	        combine_verilog_ports(instance_ports);
560	
561	      /* Print a verilog port by combining the instance ports */
562	      fp << generate_verilog_ports(merged_ports, little_endian);
563	
564	      /* if explicit port map is required, output the pair of branket */
565	      if (true == use_explicit_port_map) {
566	        fp << ")";
567	      }
568	      port_cnt++;
569	    }
570	  }
571	
572	  /* Print an end to the instance */
573	  fp << ");" << std::endl;
574	}
575	
576	/********************************************************************
577	 * Write a Verilog module to a file
578	 * This is a key function, maybe most frequently called in our Verilog writer
579	 * Note that file stream must be valid
580	 *******************************************************************/
581	void write_verilog_module_to_file(std::fstream& fp,
582	                                  const ModuleManager& module_manager,
583	                                  const ModuleId& module_id,
584	                                  const FabricVerilogOption& options) {
585	  VTR_ASSERT(true == valid_file_stream(fp));
586	
587	  /* Ensure we have a valid module_id */
588	  VTR_ASSERT(module_manager.valid_module_id(module_id));
589	
590	  /* Print module declaration */
591	  print_verilog_module_declaration(fp, module_manager, module_id,
592	                                   options.default_net_type(),
593	                                   options.little_endian());
594	
595	  /* Print an empty line as splitter */
596	  fp << std::endl;
597	
598	  /* Print internal wires */
599	  std::map<std::string, std::vector<BasicPort>> local_wires =
600	    find_verilog_module_local_wires(module_manager, module_id);
601	  for (std::pair<std::string, std::vector<BasicPort>> port_group :
602	       local_wires) {
603	    for (const BasicPort& local_wire : port_group.second) {
604	      /* When default net type is wire, we can skip single-bit wires whose LSB
605	       * is 0 */
606	      if ((VERILOG_DEFAULT_NET_TYPE_WIRE == options.default_net_type()) &&
607	          (1 == local_wire.get_width()) && (0 == local_wire.get_lsb())) {
608	        continue;
609	      }
610	      fp << generate_verilog_port(VERILOG_PORT_WIRE, local_wire, true,
611	                                  options.little_endian())
612	         << ";" << std::endl;
613	    }
614	  }
615	
616	  /* Use constant to drive undriven local wires */
617	  if (options.constant_undriven_inputs() !=
618	      FabricVerilogOption::e_undriven_input_type::NONE) {
619	    std::vector<ModuleManager::e_module_port_type> blacklist = {
620	      ModuleManager::e_module_port_type::MODULE_GLOBAL_PORT,
621	      ModuleManager::e_module_port_type::MODULE_GPIN_PORT,
622	      ModuleManager::e_module_port_type::MODULE_GPOUT_PORT,
623	      ModuleManager::e_module_port_type::MODULE_GPIO_PORT,
624	      ModuleManager::e_module_port_type::MODULE_INOUT_PORT,
625	      ModuleManager::e_module_port_type::MODULE_OUTPUT_PORT,
626	      ModuleManager::e_module_port_type::MODULE_CLOCK_PORT};
627	    std::map<std::string, std::vector<BasicPort>> local_undriven_wires;
628	    find_verilog_module_local_undriven_wires(
629	      local_undriven_wires, module_manager, module_id, blacklist);
630	    for (std::pair<std::string, std::vector<BasicPort>> port_group :
631	         local_undriven_wires) {
632	      for (const BasicPort& local_undriven_wire : port_group.second) {
633	        if (options.constant_undriven_inputs_use_bus()) {
634	          print_verilog_wire_constant_values(
635	            fp, local_undriven_wire,
636	            std::vector<size_t>(local_undriven_wire.get_width(),
637	                                options.constant_undriven_inputs_value()),
638	            options.little_endian());
639	        } else {
640	          print_verilog_wire_constant_values_bit_blast(
641	            fp, local_undriven_wire,
642	            std::vector<size_t>(local_undriven_wire.get_width(),
643	                                options.constant_undriven_inputs_value()),
644	            options.little_endian());
645	        }
646	      }
647	    }
648	  }
649	
650	  /* Print an empty line as splitter */
651	  fp << std::endl;
652	
653	  /* Print local connection (from module inputs to output! */
654	  print_verilog_comment(
655	    fp, std::string("----- BEGIN Local short connections -----"));
656	  print_verilog_module_local_short_connections(fp, module_manager, module_id,
657	                                               options.little_endian());
658	  print_verilog_comment(fp,
659	                        std::string("----- END Local short connections -----"));
660	
661	  print_verilog_comment(
662	    fp, std::string("----- BEGIN Local output short connections -----"));
663	  print_verilog_module_output_short_connections(fp, module_manager, module_id,
664	                                                options.little_endian());
665	
666	  print_verilog_comment(
667	    fp, std::string("----- END Local output short connections -----"));
668	  /* Print an empty line as splitter */
669	  fp << std::endl;
670	
671	  /* Print instances */
672	  for (ModuleId child_module : module_manager.child_modules(module_id)) {
673	    for (size_t instance :
674	         module_manager.child_module_instances(module_id, child_module)) {
675	      /* Print an instance */
676	      write_verilog_instance_to_file(
677	        fp, module_manager, module_id, child_module, instance,
678	        options.explicit_port_mapping(), options.little_endian());
679	      /* Print an empty line as splitter */
680	      fp << std::endl;
681	    }
682	  }
683	
684	  /* Print an end for the module */
685	  print_verilog_module_end(fp, module_manager.module_name(module_id),
686	                           options.default_net_type());
687	
688	  /* Print an empty line as splitter */
689	  fp << std::endl;
690	
691	  /* Print an empty line as splitter */
692	  fp << std::endl;
693	}
694	
695	} /* end namespace openfpga */
