22	/********************************************************************
23	 * A wrapper function to call the fabric Verilog generator of FPGA-Verilog
24	 *******************************************************************/
25	template <class T>
26	int write_fabric_verilog_template(T& openfpga_ctx, const Command& cmd,
27	                                  const CommandContext& cmd_context) {
28	  CommandOptionId opt_output_dir = cmd.option("file");
29	  CommandOptionId opt_explicit_port_mapping =
30	    cmd.option("explicit_port_mapping");
31	  CommandOptionId opt_constant_undriven_inputs =
32	    cmd.option("constant_undriven_inputs");
33	  CommandOptionId opt_include_timing = cmd.option("include_timing");
34	  CommandOptionId opt_print_user_defined_template =
35	    cmd.option("print_user_defined_template");
36	  CommandOptionId opt_default_net_type = cmd.option("default_net_type");
37	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
38	  CommandOptionId opt_use_relative_path = cmd.option("use_relative_path");
39	  CommandOptionId opt_little_endian = cmd.option("little_endian");
40	  CommandOptionId opt_verbose = cmd.option("verbose");
41	
42	  /* This is an intermediate data structure which is designed to modularize the
43	   * FPGA-Verilog Keep it independent from any other outside data structures
44	   */
45	  FabricVerilogOption options;
46	  options.set_output_directory(cmd_context.option_value(cmd, opt_output_dir));
47	  options.set_explicit_port_mapping(
48	    cmd_context.option_enable(cmd, opt_explicit_port_mapping));
49	  options.set_include_timing(
50	    cmd_context.option_enable(cmd, opt_include_timing));
51	  options.set_time_stamp(!cmd_context.option_enable(cmd, opt_no_time_stamp));
52	  options.set_use_relative_path(
53	    cmd_context.option_enable(cmd, opt_use_relative_path));
54	  options.set_print_user_defined_template(
55	    cmd_context.option_enable(cmd, opt_print_user_defined_template));
56	  if (true == cmd_context.option_enable(cmd, opt_default_net_type)) {
57	    options.set_default_net_type(
58	      cmd_context.option_value(cmd, opt_default_net_type));
59	  }
60	  options.set_little_endian(cmd_context.option_enable(cmd, opt_little_endian));
61	  options.set_verbose_output(cmd_context.option_enable(cmd, opt_verbose));
62	  options.set_compress_routing(openfpga_ctx.flow_manager().compress_routing());
63	  /* For perimeter cb, enable the constant-zero undriven inputs, unless it is
64	   * defined by user. Throw error if the constant inputs are not selected! */
65	  if (cmd_context.option_enable(cmd, opt_constant_undriven_inputs)) {
66	    options.set_constant_undriven_inputs(
67	      cmd_context.option_value(cmd, opt_constant_undriven_inputs));
68	  }
