494	  /* This is an intermediate data structure which is designed to modularize the
495	   * FPGA-Verilog Keep it independent from any other outside data structures
496	   */
497	  VerilogTestbenchOption options;
498	  options.set_output_directory(cmd_context.option_value(cmd, opt_hdl_dir));
499	  options.set_reference_benchmark_file_path(
500	    cmd_context.option_value(cmd, opt_reference_benchmark));
501	  options.set_verbose_output(cmd_context.option_enable(cmd, opt_verbose));
502	  options.set_print_simulation_ini(cmd_context.option_value(cmd, opt_file));
503	
504	  if (true == cmd_context.option_enable(cmd, opt_time_unit)) {
505	    options.set_time_unit(
506	      string_to_time_unit(cmd_context.option_value(cmd, opt_time_unit)));
507	  }
508	
509	  /* Identify testbench type */
510	  std::string full_tb_tag("full_testbench");
511	  std::string preconfig_tb_tag("preconfigured_testbench");
512	  if (true == cmd_context.option_enable(cmd, opt_tb_type)) {
513	    if (std::string("preconfigured_testbench") ==
