385	  const ModuleNameMap& module_name_map, const DeviceContext& device_ctx,
386	  const VprDeviceAnnotation& device_annotation, const std::string& subckt_dir,
387	  const std::string& subckt_dir_name, const FabricVerilogOption& options,
388	  const bool& verbose) {
389	  /* Create a vector to contain all the Verilog netlist names that have been
390	   * generated in this function */
391	  std::vector<std::string> netlist_names;
392	
393	  /* Enumerate the types of logical tiles, and build a module for each
394	   * Write modules for all the pb_types/pb_graph_nodes
395	   * use a Depth-First Search Algorithm to print the sub-modules
396	   * Note: DFS is the right way. Do NOT use BFS.
397	   * DFS can guarantee that all the sub-modules can be registered properly
398	   * to its parent in module manager
399	   */
400	  VTR_LOG("Writing logical tiles...");
401	  VTR_LOGV(verbose, "\n");
402	  for (const t_logical_block_type& logical_tile :
403	       device_ctx.logical_block_types) {
404	    /* Bypass empty pb_graph */
405	    if (nullptr == logical_tile.pb_graph_head) {
406	      continue;
407	    }
408	    print_verilog_logical_tile_netlist(
409	      netlist_manager, module_manager, module_name_map, device_annotation,
410	      subckt_dir, subckt_dir_name, logical_tile.pb_graph_head, options,
411	      verbose);
412	  }
413	  VTR_LOG("Writing logical tiles...");
414	  VTR_LOG("Done\n");
415	
416	  VTR_LOG("\n");
417	
418	  /* Enumerate the types of physical tiles
419	   * Use the logical tile module to build the physical tiles
420	   */
421	  VTR_LOG("Building physical tiles...");
422	  VTR_LOGV(verbose, "\n");

